jdeatina:invoke-ws.jdeatina:input-parameters:
#[output application/json
---
{
	entity: {
		entityId: attributes.queryParams.entityID as Number
	}
}]

#[output application/json
---
{
	entity: {
		entityId: attributes.queryParams.entityID as Number
	}
}]

#[output application/json
---
{
	tax: {
		taxExplanationCode: 'S',
		personCorporationCode: '',
		taxRateAreaCode: 'DEN'
	},
	dates: {
		dateOpen: |2025-07-15T14:00:00-03:00|
	},
	processing: {
		actionType: '1',
		processingVersion: 'ZJDE00002'
	},
	invoice: {
		paymentTermsCode: '',
		currencyCodeTransaction: payload.paymentCurrency,
		currencyCode: payload.paymentCurrency
	},
	credit: {
		amountCreditLimit: 2000,
		administrationCreditLimit: 2000
	},
	processAddressBook: {
		addressBook: {
			personCorporationCode: '',
			isEntityTypePayables: false,
			entityName: payload.customerName,
			address: {
				city: payload.customerCity,
				addressLine1: payload.customerAddress,
				addressLine2: '',
				stateCode: payload.customerState,
				addressLine3: '',
				addressLine4: ''
			},
			isEntityTypePurchaser: false,
			entityTypeCode: 'C',
			processing: {
				actionType: '1',
				processingVersion: ''
			}
		}
	},
	customer: {
		company: '00000'
	}
}]

#[output application/json
---
{
	"JDE Token": payload."JDE Token",
	companyName: vars.queryParameters.companyName as String,
	addressNumber: {
		entityId: vars.queryParameters.companyAB as Number
	},
	companyKey: {
		companyNumber: vars.queryParameters.companyNumber as String
	}
}]

#[output application/json
---
{
	header: {
		businessUnit: '          30',
		dateRequested: (payload.dateRequested default (now() as Date {format: "yyyy-MM-dd"})),
		deliverTo: {
			entityId: payload.deliverTo
		},
		salesOrderKey: {
			documentTypeCode: 'SO',
			documentCompany: '00001'
		},
		dateOrdered: now(),
		company: '00001',
		currencyCodeTo: 'USD',
		processing: {
			actionType: '1',
			processingVersion: 'ZJDE0001'
		},
		detail: (payload.detail default []) map (d) -> {
		      quantityOrdered: d.quantityOrdered,
		      lineTypeCode: "S",
		      product: {
		        item: {
		          itemId: d.itemId
		        }
		      },
			  processing: {
				actionType: '1'
			  }
		}, 
		shipTo: {
			customer: {
				entityId: payload.shipTo
			}
		}
	}
}]

#[output application/json
---
{
	addressBook: {
		businessUnit: '           1',
		personCorporationCode: 'C',
		isEntityTypePayables: false,
		entityName: payload.customerName,
		address: {
			mailingNameSecondary: payload.customerName,
			city: payload.customerCity,
			addressLine1: payload.customerAddress
		},
		isEntityTypeReceivables: 'C',
		entityTypeCode: 'C',
		processing: {
			actionType: '1',
			processingVersion: 'ZJDE0001'
		}
	}
}]

#[output application/java
---
{
	mediaObject: {
		moItems: [
		{
			szItemName: 'Green.gif',
			szMoType: 'FILE',
			szData: vars.gifImage
		},
		{
			szItemName: 'Readme.pdf',
			szMoType: 'FILE',
			szData: vars.pdf
		},
		{ 
			szMoType: 'TEXT',
			szData: "This is a Demo for DBCT"
		},
		{ 
			szMoType: 'URL',
			szItemName: "https://www.dbct.com.au/"
		}]
	},
	businessUnit: '1',
	entityTypeCode: 'C',
	entityName: 'Rocking14'
}]
